import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { gamesAPI, ordersAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';

interface Game {
  _id: string;
  title: string;
  description: string;
  price: number;
  platform: string;
  region: string;
  images: string[];
  availability: string;
  accountDetails: {
    username?: string;
    email?: string;
    additionalInfo?: string;
  };
}

const GameDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const { state } = useAuth();
  const navigate = useNavigate();
  const [game, setGame] = useState<Game | null>(null);
  const [loading, setLoading] = useState(true);
  const [ordering, setOrdering] = useState(false);

  useEffect(() => {
    if (id) {
      fetchGame();
    }
  }, [id]);

  const fetchGame = async () => {
    try {
      setLoading(true);
      const response = await gamesAPI.getGame(id!);
      setGame(response.data);
    } catch (error) {
      console.error('Error fetching game:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleOrder = async () => {
    if (!state.isAuthenticated) {
      navigate('/login');
      return;
    }

    try {
      setOrdering(true);
      await ordersAPI.createOrder({
        games: [{ game: game!._id, price: game!.price }]
      });
      alert('تم إنشاء الطلب بنجاح!');
      navigate('/cart');
    } catch (error: any) {
      alert(error.response?.data?.message || 'فشل إنشاء الطلب');
    } finally {
      setOrdering(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          <div className="text-center py-8">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mx-auto"></div>
            <p className="mt-4 text-gray-600">جاري التحميل...</p>
          </div>
        </div>
      </div>
    );
  }

  if (!game) {
    return (
      <div className="min-h-screen bg-gray-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          <div className="text-center py-8">
            <p className="text-gray-600 text-lg">الحساب غير موجود</p>
            <Link to="/" className="text-indigo-600 hover:text-indigo-500 mt-4 inline-block">
              العودة للرئيسية
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="bg-white rounded-lg shadow-lg overflow-hidden">
          <div className="md:flex">
            <div className="md:shrink-0 md:w-1/3">
              {game.images && game.images.length > 0 ? (
                <img
                  src={`http://localhost:5000${game.images[0]}`}
                  alt={game.title}
                  className="h-full w-full object-cover"
                />
              ) : (
                <div className="h-full w-full bg-gray-200 flex items-center justify-center">
                  <span className="text-gray-400">لا توجد صور</span>
                </div>
              )}
            </div>
            <div className="p-8 md:w-2/3">
              <div className="mb-4">
                <h1 className="text-3xl font-bold text-gray-900 mb-2">{game.title}</h1>
                <div className="flex items-center space-x-4 mb-4">
                  <span className="text-2xl font-bold text-indigo-600">${game.price}</span>
                  <span className={`px-3 py-1 text-sm rounded-full ${
                    game.availability === 'available' ? 'bg-green-100 text-green-800' :
                    game.availability === 'sold' ? 'bg-red-100 text-red-800' :
                    'bg-yellow-100 text-yellow-800'
                  }`}>
                    {game.availability === 'available' ? 'متاح' :
                     game.availability === 'sold' ? 'تم البيع' : 'محجوز'}
                  </span>
                </div>
                <div className="flex space-x-4 text-sm text-gray-500">
                  <span>المنصة: {game.platform}</span>
                  <span>المنطقة: {game.region}</span>
                </div>
              </div>

              <div className="mb-6">
                <h2 className="text-xl font-semibold mb-2">الوصف</h2>
                <p className="text-gray-600">{game.description}</p>
              </div>

              {game.accountDetails && (
                <div className="mb-6 bg-gray-50 p-4 rounded-lg">
                  <h2 className="text-xl font-semibold mb-2">تفاصيل الحساب</h2>
                  <div className="space-y-2 text-sm">
                    {game.accountDetails.username && (
                      <div>
                        <span className="font-medium">اسم المستخدم:</span> {game.accountDetails.username}
                      </div>
                    )}
                    {game.accountDetails.email && (
                      <div>
                        <span className="font-medium">البريد الإلكتروني:</span> {game.accountDetails.email}
                      </div>
                    )}
                    {game.accountDetails.additionalInfo && (
                      <div>
                        <span className="font-medium">معلومات إضافية:</span> {game.accountDetails.additionalInfo}
                      </div>
                    )}
                  </div>
                </div>
              )}

              {game.images && game.images.length > 1 && (
                <div className="mb-6">
                  <h2 className="text-xl font-semibold mb-2">صور إضافية</h2>
                  <div className="grid grid-cols-3 gap-2">
                    {game.images.slice(1).map((image, index) => (
                      <img
                        key={index}
                        src={`http://localhost:5000${image}`}
                        alt={`${game.title} ${index + 2}`}
                        className="w-full h-32 object-cover rounded"
                      />
                    ))}
                  </div>
                </div>
              )}

              {state.user ? (
                game.availability === 'available' ? (
                  <button
                    onClick={handleOrder}
                    disabled={ordering}
                    className="w-full bg-indigo-600 text-white py-3 px-6 rounded-md hover:bg-indigo-700 transition-colors disabled:opacity-50"
                  >
                    {ordering ? 'جاري الطلب...' : 'اطلب الآن'}
                  </button>
                ) : (
                  <div className="bg-red-50 border border-red-200 text-red-600 px-4 py-3 rounded text-center">
                    هذا الحساب غير متاح للشراء
                  </div>
                )
              ) : (
                <div className="bg-yellow-50 border border-yellow-200 text-yellow-600 px-4 py-3 rounded text-center">
                  يجب <Link to="/login" className="font-medium underline">تسجيل الدخول</Link> للطلب
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default GameDetail;
